class Solution {

    // Function to perform level order traversal
    levelOrder(root) {
        // Array to store result
        let ans = [];

        // Return empty array if root is null
        if (!root) return ans;

        // Queue for level order traversal
        let q = [root];

        // Loop until queue is empty
        while (q.length > 0) {
            // Get current level size
            let size = q.length;

            // Array to store current level
            let level = [];

            // Process all nodes in this level
            for (let i = 0; i < size; i++) {
                // Remove node from front of queue
                let node = q.shift();

                // Add its data to level array
                level.push(node.data);

                // Add left child if exists
                if (node.left) q.push(node.left);

                // Add right child if exists
                if (node.right) q.push(node.right);
            }

            // Add level to final result
            ans.push(level);
        }

        return ans;
    }

    // Function to get right view
    rightView(root) {
        let levels = this.levelOrder(root);
        return levels.map(level => level[level.length - 1]);
    }
}

